// pluginSummary returns a short summary string for a plugin.
func pluginSummary(p PluginInfo) string {
	parts := 0
	if len(p.Pages) > 0 {
		parts++
	}
	if len(p.Widgets) > 0 {
		parts++
	}
	if p.HasSettingsPanel {
		parts++
	}
	if parts == 0 {
		return "Registered plugin"
	}
	return strconv.Itoa(parts) + " " + pluralize(parts, "contribution", "contributions")
}

// pluralize returns singular or plural based on count.
func pluralize(count int, singular, plural string) string {
	if count == 1 {
		return singular
	}
	return plural
}

